(function(global){'use strict';const SUTHDS={version:'2.3.0',name:'SUTH Design System'};const Toast={container:null,init(){if(!this.container){this.container=document.createElement('div');this.container.className='suth-toast-container';this.container.style.cssText='position:fixed;top:20px;right:20px;z-index:9999;display:flex;flex-direction:column;gap:12px;';document.body.appendChild(this.container)}},show(message,type='success',duration=3000){this.init();const icons={success:'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--success-600)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>',error:'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--error-600)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>',warning:'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--warning-600)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',info:'<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--info-600)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg>'};const borderColors={success:'var(--success-500)',error:'var(--error-500)',warning:'var(--warning-500)',info:'var(--info-500)'};const toast=document.createElement('div');toast.style.cssText=`display:flex;align-items:center;gap:12px;padding:16px;background:var(--toast-bg,var(--card-bg,#fff));border-radius:8px;box-shadow:var(--shadow-xl,0 10px 30px -5px rgba(0,0,0,0.15));border-left:4px solid ${borderColors[type]};min-width:300px;max-width:400px;animation:slideIn 0.3s ease;color:var(--text-primary);`;toast.innerHTML=`${icons[type]}<div style="flex:1;"><div style="font-weight:600;font-size:14px;color:var(--text-primary);margin-bottom:2px;">${type.charAt(0).toUpperCase()+type.slice(1)}</div><div style="font-size:13px;color:var(--text-secondary);">${message}</div></div><button onclick="this.parentElement.remove()" style="background:none;border:none;color:var(--text-muted);cursor:pointer;padding:0;width:20px;height:20px;display:flex;align-items:center;justify-content:center;">×</button>`;this.container.appendChild(toast);setTimeout(()=>{toast.style.opacity='0';toast.style.transform='translateX(100%)';setTimeout(()=>toast.remove(),300)},duration)},success(message,duration){this.show(message,'success',duration)},error(message,duration){this.show(message,'error',duration)},warning(message,duration){this.show(message,'warning',duration)},info(message,duration){this.show(message,'info',duration)}};const Modal={open(id){const modal=document.getElementById(id);if(modal){modal.classList.add('active');document.body.style.overflow='hidden'}},close(id){const modal=typeof id==='string'?document.getElementById(id):id;if(modal){modal.classList.remove('active');document.body.style.overflow=''}},init(){document.querySelectorAll('.modal-overlay').forEach(overlay=>{overlay.addEventListener('click',(e)=>{if(e.target===e.currentTarget){this.close(e.target)}})});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'){document.querySelectorAll('.modal-overlay.active').forEach(m=>{this.close(m)})}})}};const Tabs={switch(tabBtn,tabId){const container=tabBtn.closest('.tabs');if(!container)return;container.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));container.querySelectorAll('.tab-panel').forEach(p=>p.classList.remove('active'));tabBtn.classList.add('active');const panel=document.getElementById(tabId);if(panel)panel.classList.add('active')},init(){document.querySelectorAll('.tab-btn').forEach(btn=>{btn.addEventListener('click',()=>{const tabId=btn.dataset.tab||btn.getAttribute('onclick')?.match(/'(.*?)'/)?.[1];if(tabId)this.switch(btn,tabId)})})}};const FormValidation={validate(form){const inputs=form.querySelectorAll('input[required],select[required],textarea[required]');let isValid=true;inputs.forEach(input=>{if(!this.validateField(input)){isValid=false}});return isValid},validateField(field){const formGroup=field.closest('.form-group');if(!formGroup)return true;const errorEl=formGroup.querySelector('.form-error');let isValid=true;let errorMsg='';if(!field.value.trim()){isValid=false;errorMsg='This field is required'}else if(field.type==='email'){const emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;if(!emailRegex.test(field.value)){isValid=false;errorMsg='Please enter a valid email address'}}if(!isValid){field.classList.add('error');if(errorEl){errorEl.textContent=errorMsg;errorEl.style.display='block'}}else{field.classList.remove('error');if(errorEl)errorEl.style.display='none'}return isValid},init(formSelector='form[data-validate]'){document.querySelectorAll(formSelector).forEach(form=>{form.addEventListener('submit',(e)=>{if(!this.validate(form)){e.preventDefault()}});form.querySelectorAll('input,select,textarea').forEach(input=>{input.addEventListener('blur',()=>this.validateField(input));input.addEventListener('input',()=>{if(input.classList.contains('error')){this.validateField(input)}})})})}};const DataTable={init(tableSelector='.data-table'){document.querySelectorAll(tableSelector).forEach(table=>{this.makeSortable(table)})},makeSortable(table){const headers=table.querySelectorAll('th[data-sort]');headers.forEach(header=>{header.style.cursor='pointer';header.addEventListener('click',()=>{const column=header.dataset.sort;this.sort(table,column,header)})})},sort(table,column,header){const tbody=table.querySelector('tbody');const rows=Array.from(tbody.querySelectorAll('tr'));const isAsc=!header.classList.contains('sort-asc');table.querySelectorAll('th').forEach(th=>{th.classList.remove('sort-asc','sort-desc')});header.classList.add(isAsc?'sort-asc':'sort-desc');rows.sort((a,b)=>{const aVal=a.querySelector(`td[data-column="${column}"]`)?.textContent.trim()||'';const bVal=b.querySelector(`td[data-column="${column}"]`)?.textContent.trim()||'';if(aVal<bVal)return isAsc?-1:1;if(aVal>bVal)return isAsc?1:-1;return 0});rows.forEach(row=>tbody.appendChild(row))}};const Copy={async text(text){try{await navigator.clipboard.writeText(text);Toast.success('Copied to clipboard!');return true}catch(err){Toast.error('Failed to copy');return false}},async element(element){const text=element.outerHTML||element.textContent;return this.text(text)}};const Sidebar={toggle(){const sidebar=document.querySelector('.sidebar');if(sidebar){sidebar.classList.toggle('active')}},close(){const sidebar=document.querySelector('.sidebar');if(sidebar){sidebar.classList.remove('active')}}};const Theme={get current(){return document.documentElement.getAttribute('data-theme')||(window.matchMedia&&window.matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light')},set(theme){if(theme==='light'||theme==='dark'){document.documentElement.setAttribute('data-theme',theme);localStorage.setItem('suth-ds-theme',theme)}else{document.documentElement.removeAttribute('data-theme');localStorage.removeItem('suth-ds-theme')}},toggle(){const next=this.current==='dark'?'light':'dark';this.set(next);return next},init(){const saved=localStorage.getItem('suth-ds-theme');if(saved){this.set(saved)}}};const Animations={fadeIn(element,duration=300){element.style.opacity='0';element.style.display='block';element.style.transition=`opacity ${duration}ms ease`;requestAnimationFrame(()=>{element.style.opacity='1'})},fadeOut(element,duration=300){element.style.transition=`opacity ${duration}ms ease`;element.style.opacity='0';setTimeout(()=>{element.style.display='none'},duration)}};SUTHDS.init=function(){Theme.init();Modal.init();Tabs.init();FormValidation.init();DataTable.init();console.log(`%c${this.name} v${this.version}`,'color:#2563EB;font-weight:bold;font-size:14px;');console.log('%cReady to use! \ud83d\ude80','color:#059669;')};SUTHDS.toast=Toast;SUTHDS.modal=Modal;SUTHDS.tabs=Tabs;SUTHDS.form=FormValidation;SUTHDS.table=DataTable;SUTHDS.copy=Copy;SUTHDS.sidebar=Sidebar;SUTHDS.animate=Animations;SUTHDS.theme=Theme;global.SUTHDS=SUTHDS;global.SuthDS=SUTHDS;if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>SUTHDS.init())}else{SUTHDS.init()}})(window);